export type BlockType = 'brick' | 'question' | 'solid' | 'ground' | 'empty' | 'spike' | 'pipe_top' | 'pipe_body' | 'pipe_end_top' | 'pipe_end_body' | 'coin' | 'vine' | 'moving_h' | 'moving_v' | 'fan' | 'fan_wind' | 'jump_pad' | 'powerup_fire' | 'powerup_cat' | 'powerup_wing';
export type DecoType = 'cloud' | 'hill_small' | 'hill_large';

export interface Block {
  type: BlockType;
  x: number;
  y: number;
  width: number;
  height: number;
  collected?: boolean;
  vx?: number;
  vy?: number;
  startX?: number;
  startY?: number;
  timer?: number;
}

export interface Enemy {
  type: 'goomba' | 'jumper' | 'shooter';
  x: number;
  y: number;
  vx: number;
  vy: number;
  width: number;
  height: number;
  dead: boolean;
  timer?: number;
}

export interface Deco {
  type: DecoType;
  x: number;
  y: number;
}

export function parseLevel(levelIndex: number): { blocks: Block[], decos: Deco[], enemies: Enemy[], width: number, height: number } {
  const blocks: Block[] = [];
  const decos: Deco[] = [];
  const enemies: Enemy[] = [];
  const levelMap = LEVELS[levelIndex % LEVELS.length];
  const height = levelMap.length * TILE_SIZE;
  const width = levelMap[0].length * TILE_SIZE;

  for (let y = 0; y < levelMap.length; y++) {
    const row = levelMap[y];
    for (let x = 0; x < row.length; x++) {
      const char = row[x];
      const bx = x * TILE_SIZE;
      const by = y * TILE_SIZE;

      if (char === 'G') blocks.push({ type: 'ground', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'b') blocks.push({ type: 'brick', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === '?') blocks.push({ type: 'question', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 's') blocks.push({ type: 'solid', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      // Shorter spikes for easier jumping
      else if (char === '^') blocks.push({ type: 'spike', x: bx, y: by + 12, width: TILE_SIZE, height: 4 });
      else if (char === 'p') blocks.push({ type: 'jump_pad', x: bx, y: by + TILE_SIZE/2, width: TILE_SIZE, height: TILE_SIZE/2 });
      else if (char === 'F') blocks.push({ type: 'powerup_fire', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'C') blocks.push({ type: 'powerup_cat', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'W') blocks.push({ type: 'powerup_wing', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === '|') blocks.push({ type: 'pipe_body', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === '>') blocks.push({ type: 'pipe_top', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === '[') blocks.push({ type: 'pipe_end_body', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === ']') blocks.push({ type: 'pipe_end_top', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'o') blocks.push({ type: 'coin', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'v') blocks.push({ type: 'vine', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      
      // New Elements
      else if (char === 'f') blocks.push({ type: 'fan', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'w') blocks.push({ type: 'fan_wind', x: bx, y: by, width: TILE_SIZE, height: TILE_SIZE });
      else if (char === 'm') blocks.push({ type: 'moving_h', x: bx, y: by, width: TILE_SIZE * 2, height: 8, vx: 0.8, startX: bx });
      else if (char === 'M') blocks.push({ type: 'moving_v', x: bx, y: by, width: TILE_SIZE * 2, height: 8, vy: 0.8, startY: by });
      
      else if (char === 'e') enemies.push({ type: 'goomba', x: bx, y: by, vx: -1, vy: 0, width: 14, height: 14, dead: false });
      else if (char === 'j') enemies.push({ type: 'jumper', x: bx, y: by, vx: 0, vy: 0, width: 14, height: 14, dead: false, timer: 0 });
      else if (char === 't') enemies.push({ type: 'shooter', x: bx, y: by, vx: 0, vy: 0, width: 14, height: 14, dead: false, timer: 0 });

      else if (char === 'c') decos.push({ type: 'cloud', x: bx, y: by });
      else if (char === 'h') decos.push({ type: 'hill_small', x: bx, y: by });
      else if (char === 'H') decos.push({ type: 'hill_large', x: bx, y: by });
    }
  }

  return { blocks, decos, enemies, width, height };
}
